// --- SERIES PRO: POST GUNCELLEME ---
if ( class_exists('DLEPlugins') && DLEPlugins::Check('DLE Real Series PRO') ) {
    $pro_id = intval($id); 
    if(!$pro_id && isset($added_item)) $pro_id = intval($added_item);
    if(!$pro_id && isset($item_db[0])) $pro_id = intval($item_db[0]);
    if(!$pro_id) $pro_id = intval($db->insert_id());

    if($pro_id > 0) {
        $is_series_save      = isset($_POST['is_series'])      ? intval($_POST['is_series'])      : 0;
        $series_parent_save  = isset($_POST['series_parent'])  ? intval($_POST['series_parent'])  : 0;
        $series_season_save  = isset($_POST['series_season'])  ? intval($_POST['series_season'])  : 0;
        $series_episode_save = isset($_POST['series_episode']) ? intval($_POST['series_episode']) : 0;

        $db->query("UPDATE " . PREFIX . "_post SET is_series='{$is_series_save}', series_parent='{$series_parent_save}', series_season='{$series_season_save}', series_episode='{$series_episode_save}' WHERE id='{$pro_id}'");

        if(isset($_POST['series_tmdb_id']) && trim($_POST['series_tmdb_id'])) {
            $series_tmdb_id = intval($_POST['series_tmdb_id']);
            $r_xf = $db->super_query("SELECT xfields FROM " . PREFIX . "_post WHERE id='{$pro_id}'");
            $xf = $r_xf['xfields'];
            if(preg_match('/series_tmdb_id\|.*?(\|\||$)/', $xf)) {
                $xf = preg_replace('/series_tmdb_id\|.*?(\|\||$)/', 'series_tmdb_id|'.$series_tmdb_id.'||', $xf);
            } else {
                $xf = ($xf ? $xf.'||' : '') . 'series_tmdb_id|'.$series_tmdb_id;
            }
            $xf = rtrim($xf, "||");
            $db->query("UPDATE " . PREFIX . "_post SET xfields='".$db->safesql($xf)."' WHERE id='{$pro_id}'");
        }
    }
}
