function spLoadSezonlar(diziId, preSezon){
	$.post("index.php?controller=ajax&mod=series_fetch", { action: "list_sezonlar", q: "", user_hash: dle_login_hash }, function(r){
		var opts = '<option value="">— Sezon Seçin —</option>';
		r.filter(function(s){ return parseInt(s.series_parent) === parseInt(diziId); })
		 .sort(function(a,b){ return a.series_season - b.series_season; })
		 .forEach(function(s){ opts += '<option value="'+s.series_season+'"'+( parseInt(s.series_season)===parseInt(preSezon) ? ' selected' : '' )+'>'+s.title+'</option>'; });
		$("#sp_sezon_sel").html(opts);
		$("#sp_sezon_wrap").show();
	}, "json");
}

function spOnDiziChange(val){
	var v = parseInt($("#is_series_select").val());
	$("#series_parent_input").val(val || 0);
	var selOpt = $("#sp_dizi_sel option:selected");
	if(selOpt.data("tmdb")) $("#tmdb_id").val(selOpt.data("tmdb"));
	if(v === 3 && val){ spLoadSezonlar(val, 0); } else { $("#sp_sezon_wrap").hide(); }
}

function spOnSezonChange(val){ if(val) $("#series_season").val(val); }
</script>
HTML;
}
