    $sb_episode_display  = ($is_series == 3) ? '' : 'display:none;';
    $tmdb_display        = ($is_series == 1 || $is_series == 2 || $is_series == 3) ? '' : 'display:none;';

$series_panel = <<<HTML
<div class="panel panel-flat" style="margin-bottom:20px;background:#f9f9f9;padding:15px;border:1px solid #ddd;">
   <div class="row">
		<div class="col-md-3">
			<label>İÇERİK TÜRÜ</label>
			<select name="is_series" id="is_series_select" class="form-control">
				<option value="0" {$sel_0}>Normal Haber</option>
				<option value="1" {$sel_1}>🎬 Dizi Ana Sayfası</option>
				<option value="2" {$sel_2}>📋 Sezon</option>
				<option value="3" {$sel_3}>▶ Bölüm</option>
			</select>
		</div>
		<div class="col-md-4" id="sp_dizi_wrap" style="{$dizi_display}">
			<label>Bağlı Dizi</label>
			<select id="sp_dizi_sel" class="form-control" onchange="spOnDiziChange(this.value)">
				<option value="">— Dizi Seçin —</option>
			</select>
			<input type="hidden" name="series_parent" id="series_parent_input" value="{$series_parent}">
		</div>
		<div class="col-md-3" id="sp_sezon_wrap" style="{$sezon_display}">
			<label>Bağlı Sezon</label>
			<select id="sp_sezon_sel" class="form-control" onchange="spOnSezonChange(this.value)">
				<option value="">— Sezon Seçin —</option>
			</select>
		</div>
		<div class="col-md-2" id="sb_season_wrap" style="{$sb_season_display}">
