				</span>
			</div>
		</div>
   </div>
</div>
<script>
var spCurrentDiziId = {$series_parent};
var spCurrentSezon  = {$series_season};

$(function(){
	$("#is_series_select").on("change", function(){
		var v = parseInt($(this).val());
		$("#sp_dizi_wrap, #sp_sezon_wrap, #sb_season_wrap, #sb_episode_wrap, #sp_tmdb_wrap").hide();
		if(v === 1){
			$("#sp_tmdb_wrap").show();
		} else if(v === 2){
			$("#sp_dizi_wrap, #sb_season_wrap, #sp_tmdb_wrap").show();
			spLoadDiziler(spCurrentDiziId);
		} else if(v === 3){
			$("#sp_dizi_wrap, #sb_season_wrap, #sb_episode_wrap, #sp_tmdb_wrap").show();
			spLoadDiziler(spCurrentDiziId, spCurrentSezon);
		}
	});

	var initType = parseInt($("#is_series_select").val());
	if(initType === 2 || initType === 3){ spLoadDiziler(spCurrentDiziId, initType === 3 ? spCurrentSezon : 0); }

	$("#btn_tmdb_fetch").off("click").on("click", function(){
		var tid = $("#tmdb_id").val();
		if(!tid){ DLEPush.error("ID girin"); return; }
		DLEconfirm("Mevcut veriler güncellenecek. Onaylıyor musunuz?", "TMDB Güncelleme", function(){
			ShowLoading("");
			$.post("index.php?controller=ajax&mod=series_tmdb", {
				tmdb_id: tid, type: $("#is_series_select").val(), season: $("#series_season").val(), episode: $("#series_episode").val(), user_hash: dle_login_hash
			}, function(d){
				HideLoading("");
				if(d.error){ DLEalert(d.error, "Hata"); return; }
				var xf = {$xf_map_json};
				$("input[name='title']").val(d.name||d.title||"");
				if(d.overview){ if(typeof tinyMCE!=="undefined") tinyMCE.get("short_story").setContent(d.overview); else $("#short_story").val(d.overview); }
				function S(k,v){ if(xf[k]&&v) $('[name="xfield['+xf[k]+']"]').val(v); }
				S("original_name",d.original_name); S("original_language",d.original_language); S("status",d.status);
				S("vote_average",d.vote_average); S("vote_count",d.vote_count); S("homepage",d.homepage);
				S("number_of_seasons",d.number_of_seasons); S("number_of_episodes",d.number_of_episodes);
				S("last_air_date",d.last_air_date); S("tagline",d.tagline); S("in_production",d.in_production); S("popularity",d.popularity);
				S("adult", d.adult==true?"1":"0");
				if(d.poster_path) S("poster_path","https://image.tmdb.org/t/p/original"+d.poster_path);
				if(d.backdrop_path) S("backdrop_path","https://image.tmdb.org/t/p/original"+d.backdrop_path);
				if(d.first_air_date) S("year", d.first_air_date.split("-")[0]);
				if(d.genres) S("genres", d.genres.map(function(i){return i.name;}).join(", "));
				if(d.production_companies) S("production_companies", d.production_companies.map(function(i){return i.name;}).join(", "));
				if(d.production_countries) S("production_countries", d.production_countries.map(function(i){return i.name;}).join(", "));
				if(d.networks) S("networks", d.networks.map(function(i){return i.name;}).join(", "));
				if(d.origin_country) S("origin_country", d.origin_country.join(", "));
				if(d.content_ratings&&d.content_ratings.results){ var r=d.content_ratings.results.find(function(x){return x.iso_3166_1==="TR";})||d.content_ratings.results.find(function(x){return x.iso_3166_1==="US";}); if(r) S("age_limit",r.rating); }
				if(d.spoken_languages) S("spoken_languages", d.spoken_languages.map(function(l){return l.english_name||l.name;}).join(", "));
				if(d.credits){ if(d.credits.cast) S("cast", d.credits.cast.slice(0,15).map(function(c){return c.name;}).join(", ")); if(d.credits.crew){ var dir=d.credits.crew.find(function(c){return c.job==="Director";}); if(dir) S("created_by",dir.name); } }
				if(d.videos&&d.videos.results){ var v=d.videos.results.find(function(t){return t.site==="YouTube"&&t.type==="Trailer";}); if(v){ S("trailer_url","https://www.youtube.com/watch?v="+v.key); S("trailer_embed",'<iframe width="560" height="315" src="https://www.youtube.com/embed/'+v.key+'" frameborder="0" allowfullscreen></iframe>'); } }
				$("#tmdb_id").val(tid);
				DLEPush.info("Veriler Çekildi!");
			}, "json");
		});
	});
});

function spLoadDiziler(preselect, preSezon){
	$.post("index.php?controller=ajax&mod=series_fetch", { action: "list_diziler", q: "", user_hash: dle_login_hash }, function(r){
		var opts = '<option value="">— Dizi Seçin —</option>';
		r.forEach(function(d){ opts += '<option value="'+d.id+'" data-tmdb="'+d.tmdb_id+'"'+( parseInt(d.id)===parseInt(preselect) ? ' selected' : '' )+'>'+d.title+'</option>'; });
		$("#sp_dizi_sel").html(opts);
		if(preselect && parseInt($("#is_series_select").val()) === 3){ spLoadSezonlar(preselect, preSezon); }
	}, "json");
}

function spLoadSezonlar(diziId, preSezon){
	$.post("index.php?controller=ajax&mod=series_fetch", { action: "list_sezonlar", q: "", user_hash: dle_login_hash }, function(r){
		var opts = '<option value="">— Sezon Seçin —</option>';
		r.filter(function(s){ return parseInt(s.series_parent) === parseInt(diziId); })
		 .sort(function(a,b){ return a.series_season - b.series_season; })
		 .forEach(function(s){ opts += '<option value="'+s.series_season+'"'+( parseInt(s.series_season)===parseInt(preSezon) ? ' selected' : '' )+'>'+s.title+'</option>'; });
		$("#sp_sezon_sel").html(opts);
		$("#sp_sezon_wrap").show();
	}, "json");
}

function spOnDiziChange(val){
	var v = parseInt($("#is_series_select").val());
	$("#series_parent_input").val(val || 0);
	var selOpt = $("#sp_dizi_sel option:selected");
	if(selOpt.data("tmdb")) $("#tmdb_id").val(selOpt.data("tmdb"));
	if(v === 3 && val){ spLoadSezonlar(val, 0); } else { $("#sp_sezon_wrap").hide(); }
}

function spOnSezonChange(val){ if(val) $("#series_season").val(val); }
</script>
HTML;
}
