$_sv = isset($row['is_series']) ? intval($row['is_series']) : 0;
$_xf = isset($row['xfields']) ? $row['xfields'] : '';
if ($_sv == 2) {
	preg_match('/season_poster\|(.*?)(?:\|\||$)/', $_xf, $_m);
	if (!empty($_m[1]) && strpos($_xf,'poster_path|')===false) $row['xfields'] .= ($_xf?'||':'').'poster_path|'.trim($_m[1]);
	preg_match('/season_vote_average\|(.*?)(?:\|\||$)/', $_xf, $_m);
	if (!empty($_m[1])) {
		if (strpos($_xf,'vote_average|')===false) $row['xfields'] .= '||vote_average|'.trim($_m[1]);
		if (strpos($_xf,'imdb_rating|')===false) $row['xfields'] .= '||imdb_rating|'.trim($_m[1]);
	}
	preg_match('/season_year\|(.*?)(?:\|\||$)/', $_xf, $_m);
	if (!empty($_m[1]) && strpos($_xf,'year|')===false) $row['xfields'] .= '||year|'.trim($_m[1]);
} elseif ($_sv == 3) {
	preg_match('/episode_image\|(.*?)(?:\|\||$)/', $_xf, $_m);
	if (empty($_m[1])) preg_match('/season_poster\|(.*?)(?:\|\||$)/', $_xf, $_m);
	if (!empty($_m[1]) && strpos($_xf,'poster_path|')===false) $row['xfields'] .= ($_xf?'||':'').'poster_path|'.trim($_m[1]);
	preg_match('/episode_vote\|(.*?)(?:\|\||$)/', $_xf, $_m);
	if (!empty($_m[1])) {
		if (strpos($_xf,'vote_average|')===false) $row['xfields'] .= '||vote_average|'.trim($_m[1]);
		if (strpos($_xf,'imdb_rating|')===false) $row['xfields'] .= '||imdb_rating|'.trim($_m[1]);
	}
	preg_match('/episode_year\|(.*?)(?:\|\||$)/', $_xf, $_m);
	if (!empty($_m[1]) && strpos($_xf,'year|')===false) $row['xfields'] .= '||year|'.trim($_m[1]);
}
